function bindAddonVerificacionEvents() {
    const body = document.getElementById("ventasAddonDetailBody");

    if (!body) return;

    body.querySelectorAll(".addon-verificacion-check").forEach(function(chk) {
        chk.addEventListener("change", async function() {
            const idventaaddon = this.dataset.idventaaddon;
            const valor = this.checked ? 1 : 0;

            if (!idventaaddon) {
                alert("No se pudo identificar el addon.");
                return;
            }

            await guardarVerificacionAddon(idventaaddon, valor, this);
        });
    });
}



async function guardarVerificacionAddon(idventaaddon, valor, checkbox) {
    const valorAnterior = checkbox.checked ? 0 : 1;

    try {
        checkbox.disabled = true;

        const resp = await fetch("custom/php/ventas_addons_update.php", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({
                idventaaddon: idventaaddon,
                verificacion_realizada: valor
            })
        });

        const txt = await resp.text();
        let result = {};

        try {
            result = JSON.parse(txt);
        } catch (e) {
            throw new Error("Respuesta JSON inválida: " + txt);
        }

        if (!result.success) {
            throw new Error(result.message || "No se pudo actualizar la verificación.");
        }

        checkbox.classList.add("addon-check-saved");

        setTimeout(function() {
            checkbox.classList.remove("addon-check-saved");
        }, 700);

        if (result.parent) {
            actualizarFilaPadreAddon(result.parent);
        }

    } catch (e) {
        console.error("Error guardando verificación:", e);

        checkbox.checked = valorAnterior === 1;

        alert(e.message || "No se pudo guardar la verificación.");
    } finally {
        checkbox.disabled = false;
    }
}



function actualizarFilaPadreAddon(parentData) {
    if (!ventasGridApi || !parentData || !parentData.idventa) {
        return;
    }

    const idventa = String(parentData.idventa);
    let nodoEncontrado = null;

    ventasGridApi.forEachNode(function(node) {
        if (!node || !node.data) return;

        if (String(node.data.idventa) === idventa) {
            nodoEncontrado = node;
        }
    });

    if (!nodoEncontrado) {
        return;
    }

    Object.assign(nodoEncontrado.data, {
        seguro_capturado: parentData.seguro_capturado,
        seguro_verificado: parentData.seguro_verificado,
        control_capturado: parentData.control_capturado,
        control_verificado: parentData.control_verificado,
        nfs_capturado: parentData.nfs_capturado,
        nfs_verificado: parentData.nfs_verificado,
        addons_count: parentData.addons_count
    });

    ventasGridApi.refreshCells({
        rowNodes: [nodoEncontrado],
        columns: [
            "seguro_capturado",
            "seguro_verificado",
            "control_capturado",
            "control_verificado",
            "nfs_capturado",
            "nfs_verificado",
            "addons_count",
            "addons_toggle"
        ],
        force: true
    });
}






