function NumeroEditorVentas() {}

NumeroEditorVentas.prototype.init = function(params) {
    this.params = params;

    this.eInput = document.createElement("input");
    this.eInput.type = "text";
    this.eInput.className = "ag-input-field-input ag-text-field-input";
    this.eInput.value = params.value === null || params.value === undefined ? "" : String(params.value);

    this.eInput.addEventListener("keydown", function(e) {
        const permitidas = [
            "Backspace", "Delete", "Tab", "Enter", "Escape",
            "ArrowLeft", "ArrowRight", "Home", "End"
        ];

        if (permitidas.includes(e.key)) {
            return;
        }

        if (e.key >= "0" && e.key <= "9") {
            return;
        }

        if (e.key === "." && !this.value.includes(".")) {
            return;
        }

        e.preventDefault();
    });
};

NumeroEditorVentas.prototype.getGui = function() {
    return this.eInput;
};

NumeroEditorVentas.prototype.afterGuiAttached = function() {
    this.eInput.focus();
    this.eInput.select();
};

NumeroEditorVentas.prototype.getValue = function() {
    return this.eInput.value;
};

NumeroEditorVentas.prototype.destroy = function() {};


function columnaNumeroVentas(field, headerName, opciones) {
    opciones = opciones || {};

    return {
        colId: field,
        field: field,
        headerName: headerName,
        minWidth: opciones.minWidth || 140,
        maxWidth: opciones.maxWidth || undefined,
        editable: opciones.editable === true,
        cellClass: opciones.editable === true ? "ventas-cell-editable" : "",
        filter: "agNumberColumnFilter",
        floatingFilter: true,

        cellEditor: NumeroEditorVentas,

        cellEditorParams: {
            min: opciones.min !== undefined ? opciones.min : undefined,
            max: opciones.max !== undefined ? opciones.max : undefined,
            precision: opciones.precision !== undefined ? opciones.precision : 2
        },

        valueFormatter: function(params) {
            if (params.value === null || params.value === undefined || params.value === "") {
                return "";
            }

            const n = Number(params.value);

            if (isNaN(n)) {
                return params.value;
            }

            return n.toLocaleString("es-MX", {
                minimumFractionDigits: opciones.decimales || 0,
                maximumFractionDigits: opciones.decimales !== undefined ? opciones.decimales : 2
            });
        },

        valueSetter: function(params) {
            let nuevoValor = params.newValue;

            if (nuevoValor === null || nuevoValor === undefined || nuevoValor === "") {
                params.data[field] = null;
                return true;
            }

            nuevoValor = String(nuevoValor).replace(/,/g, "").trim();

            if (!/^-?\d+(\.\d+)?$/.test(nuevoValor)) {
                alert("Solo se permiten números en " + headerName + ".");
                return false;
            }

            params.data[field] = Number(nuevoValor);
            return true;
        }
    };
}











