function normalizeVentasValue(value) {
    if (value === undefined || value === null) return "";
    return value;
}

async function guardarCambioVentas(params) {
    const row = params.data || {};
    const field = params.colDef ? params.colDef.field : "";

    if (!row.idventa || !field) {
        return;
    }

    try {
        const resp = await fetch("custom/php/ventas_aggrid_update.php", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({
                idventa: row.idventa,
                campo: field,
                valor: normalizeVentasValue(params.newValue)
            })
        });

        const txt = await resp.text();
        let result = {};

        try {
            result = JSON.parse(txt);
        } catch (e) {
            throw new Error("Respuesta JSON invalida: " + txt);
        }

        if (!result.success) {
            throw new Error(result.message || "No fue posible guardar el cambio");
        }

        if (result.row && ventasGridApi) {
            Object.assign(row, result.row);
            ventasGridApi.refreshCells({
                rowNodes: [params.node],
                force: true
            });
        }
    } catch (e) {
        console.error("No se pudo guardar cambio de ventas:", e);
        params.node.setDataValue(field, params.oldValue);
        alert(e.message || "No se pudo guardar el cambio.");
    }
}


