    if (!ventasGridApi) return;

    try {
        const raw = localStorage.getItem(getColumnPrefsKey());
        if (!raw) return;

        const state = JSON.parse(raw);
        if (Array.isArray(state) && state.length) {
            ventasGridApi.applyColumnState({
                state: state,
                applyOrder: true
            });
        }
    } catch (e) {
        console.error("No se pudo restaurar estado de columnas", e);
    }
}

function renderColumnPanel() {
    if (!ventasGridApi) return;

    const container = document.getElementById("ventasColumnList");
    if (!container) return;

    const allCols = ventasGridApi.getColumns() || [];
    let html = "";

    allCols.forEach(function(col) {
        const colDef = col.getColDef();
        const colId = col.getColId();
        const header = colDef.headerName || colId;
        const visible = col.isVisible();

        // ocultamos columnas especiales que no quieras tocar
        if (colId === "sel") return;

        html += `
            <label class="ventas-column-item">
                <input type="checkbox" class="ventas-col-toggle" data-colid="${colId}" ${visible ? "checked" : ""}>
                <span>${header}</span>
            </label>
        `;
    });

    container.innerHTML = html;

    container.querySelectorAll(".ventas-col-toggle").forEach(function(chk) {
        chk.addEventListener("change", function() {
            const colId = this.dataset.colid;
            const visible = !!this.checked;

            ventasGridApi.setColumnsVisible([colId], visible);
            guardarEstadoColumnas();
        });
    });
}


function activarFiltroSoloConEnter() {
    const gridDiv = document.querySelector("#myGrid");

    if (!gridDiv || !ventasGridApi) return;

    gridDiv.addEventListener("keydown", async function(e) {
        if (e.key !== "Enter") return;

        const target = e.target;
        if (!target) return;

        const estaEnFiltro =
            target.closest(".ag-floating-filter") ||
            target.closest(".ag-filter");

        if (!estaEnFiltro) return;

        const headerCell = target.closest(".ag-header-cell");
        if (!headerCell) return;

        const colId = headerCell.getAttribute("col-id");
        if (!colId) return;

        e.preventDefault();
        e.stopPropagation();
        e.stopImmediatePropagation();

        const valor = target.value !== undefined ? String(target.value).trim() : "";

        let modeloFiltro = null;

        if (valor !== "") {
            if (colId === "idventa" || colId === "addons_count") {
                modeloFiltro = {
                    filterType: "number",
                    type: "equals",
                    filter: Number(valor)
                };
            } else {
                modeloFiltro = {
                    filterType: "text",
                    type: "contains",
                    filter: valor
                };
            }
        }

        try {
            if (typeof ventasGridApi.setColumnFilterModel === "function") {
                await ventasGridApi.setColumnFilterModel(colId, modeloFiltro);
            } else {
                const filterModel = ventasGridApi.getFilterModel() || {};

                if (modeloFiltro) {
                    filterModel[colId] = modeloFiltro;
                } else {
                    delete filterModel[colId];
                }

                ventasGridApi.setFilterModel(filterModel);
            }

            ventasGridApi.onFilterChanged();

            if (typeof ventasGridApi.purgeInfiniteCache === "function") {
                ventasGridApi.purgeInfiniteCache();
            }

        } catch (err) {
            console.error("No se pudo aplicar filtro con Enter:", err);
        }

    }, true);
}


